(() => {
if (!document.body.classList.contains("page-memories")) return;
try {
document.addEventListener("DOMContentLoaded", function () {
const numberedImages = [];
for (let number = 1; number <= 112; number += 1) {
numberedImages.push(number + ".jpeg");
}
const namedImages = [
"24.webp",
"23.webp",
"25.webp",
"22.webp",
"19.webp",
"4x4.webp",
"raft2.webp",
"raft3.webp",
"vtt.webp",
"quad.webp",
"bab2.webp",
"bab3.webp",
"babmsfrane.webp",
"IMG_3580.webp",
"IMG_4728.webp",
"IMG_4826.webp",
"IMG_4832.webp",
"IMG_4850.webp",
"IMG_5128.jpg",
"IMG_5131.webp",
"IMG_5134.webp",
"IMG_7364.webp",
"IMG_7422.webp",
"IMG_7430.webp",
"IMG_7431.webp",
"IMG_7433.webp",
"IMG_7716.webp",
"IMG_7717.webp",
"IMG_7733.webp",
"benilouidan.webp",
"camping-1.webp",
"camping-2.webp",
"camping-3.webp",
"camping-4.jpg",
"blog-msfrane.webp",
"blog-cascades.webp",
"blog-gorges.webp",
"blog-tilouguite.webp",
"blog-oued-ahansal.webp",
"guide.webp",
"house.jpg",
"logo.webp"
];
const imageNames = [
...new Set([
...numberedImages,
...namedImages
])
].filter(function (name) {
return name !== "logo.webp";
});
const galleryGrid =
document.getElementById("memoriesGalleryGrid");
const loadMoreButton =
document.getElementById("loadMorePhotos");
const displayedPhotoCount =
document.getElementById("displayedPhotoCount");
const availablePhotoCount =
document.getElementById("availablePhotoCount");
const memoriesEmpty =
document.getElementById("memoriesEmpty");
const lightbox =
document.getElementById("memoriesLightbox");
const lightboxImage =
document.getElementById("lightboxImage");
const lightboxCaption =
document.getElementById("lightboxCaption");
const lightboxCurrent =
document.getElementById("lightboxCurrent");
const lightboxTotal =
document.getElementById("lightboxTotal");
const lightboxClose =
document.getElementById("lightboxClose");
const lightboxPrev =
document.getElementById("lightboxPrev");
const lightboxNext =
document.getElementById("lightboxNext");
const batchSize = 20;
let nextImageIndex = 0;
let currentLightboxIndex = 0;
let availableImages = [];
let renderedImages = [];
let loadingBatch = false;
let touchStartX = 0;
let touchEndX = 0;
function createAltText(fileName) {
const cleanName = fileName
.replace(/\.[^/.]+$/, "")
.replace(/[-_]/g, " ");
return "Imsfrane Cathédrale photo — " + cleanName;
}
function updateCounters() {
displayedPhotoCount.textContent =
renderedImages.length;
availablePhotoCount.textContent =
availableImages.length;
lightboxTotal.textContent =
renderedImages.length;
}
function testImage(fileName) {
return new Promise(function (resolve) {
const image = new Image();
image.onload = function () {
resolve({
fileName: fileName,
src: "../images/" + fileName,
alt: createAltText(fileName)
});
};
image.onerror = function () {
resolve(null);
};
image.src = "../images/" + fileName;
});
}
function createGalleryItem(imageData, galleryIndex) {
const figure =
document.createElement("figure");
figure.className = "memory-item";
figure.tabIndex = 0;
figure.setAttribute(
"role",
"button"
);
figure.setAttribute(
"aria-label",
"Open photo " + (galleryIndex + 1)
);
const image =
document.createElement("img");
image.src = imageData.src;
image.alt = imageData.alt;
image.loading = "lazy";
image.decoding = "async";
figure.appendChild(image);
figure.addEventListener(
"click",
function () {
openLightbox(galleryIndex);
}
);
figure.addEventListener(
"keydown",
function (event) {
if (
event.key === "Enter" ||
event.key === " "
) {
event.preventDefault();
openLightbox(galleryIndex);
}
}
);
return figure;
}
async function loadNextBatch() {
if (loadingBatch) {
return;
}
loadingBatch = true;
loadMoreButton.disabled = true;
let addedInThisBatch = 0;
while (
nextImageIndex < imageNames.length &&
addedInThisBatch < batchSize
) {
const fileName =
imageNames[nextImageIndex];
nextImageIndex += 1;
const imageData =
await testImage(fileName);
if (!imageData) {
continue;
}
availableImages.push(imageData);
const galleryIndex =
renderedImages.length;
renderedImages.push(imageData);
galleryGrid.appendChild(
createGalleryItem(
imageData,
galleryIndex
)
);
addedInThisBatch += 1;
}
updateCounters();
if (
nextImageIndex >= imageNames.length
) {
loadMoreButton.classList.add("hidden");
} else {
loadMoreButton.classList.remove("hidden");
}
if (
renderedImages.length === 0 &&
nextImageIndex >= imageNames.length
) {
memoriesEmpty.classList.add("show");
} else {
memoriesEmpty.classList.remove("show");
}
loadingBatch = false;
loadMoreButton.disabled = false;
}
loadMoreButton.addEventListener(
"click",
loadNextBatch
);
function updateLightbox() {
if (!renderedImages.length) {
return;
}
const imageData =
renderedImages[currentLightboxIndex];
lightboxImage.src = imageData.src;
lightboxImage.alt = imageData.alt;
lightboxCaption.textContent =
imageData.fileName;
lightboxCurrent.textContent =
currentLightboxIndex + 1;
lightboxTotal.textContent =
renderedImages.length;
}
function openLightbox(index) {
currentLightboxIndex = index;
updateLightbox();
lightbox.classList.add("open");
document.body.style.overflow = "hidden";
lightboxClose.focus();
}
function closeLightbox() {
lightbox.classList.remove("open");
document.body.style.overflow = "";
}
function changeLightbox(direction) {
if (!renderedImages.length) {
return;
}
currentLightboxIndex += direction;
if (currentLightboxIndex < 0) {
currentLightboxIndex =
renderedImages.length - 1;
}
if (
currentLightboxIndex >=
renderedImages.length
) {
currentLightboxIndex = 0;
}
updateLightbox();
}
lightboxClose.addEventListener(
"click",
closeLightbox
);
lightboxPrev.addEventListener(
"click",
function () {
changeLightbox(-1);
}
);
lightboxNext.addEventListener(
"click",
function () {
changeLightbox(1);
}
);
lightbox.addEventListener(
"click",
function (event) {
if (
event.target === lightbox ||
event.target.classList.contains(
"memories-lightbox-stage"
)
) {
closeLightbox();
}
}
);
document.addEventListener(
"keydown",
function (event) {
if (
!lightbox.classList.contains("open")
) {
return;
}
if (event.key === "Escape") {
closeLightbox();
}
if (event.key === "ArrowLeft") {
changeLightbox(-1);
}
if (event.key === "ArrowRight") {
changeLightbox(1);
}
}
);
lightbox.addEventListener(
"touchstart",
function (event) {
touchStartX =
event.changedTouches[0].screenX;
},
{
passive: true
}
);
lightbox.addEventListener(
"touchend",
function (event) {
touchEndX =
event.changedTouches[0].screenX;
const swipeDistance =
touchEndX - touchStartX;
if (
Math.abs(swipeDistance) < 45
) {
return;
}
if (swipeDistance > 0) {
changeLightbox(-1);
} else {
changeLightbox(1);
}
},
{
passive: true
}
);
loadNextBatch();
});
} catch (error) {
console.error("Imsfrane memories module error:", error);
}
})();
